def debiased_pairwise(
    case_id: str,
    user_input: str,
    response_x: str,
    response_y: str,
    label_x: str,
    label_y: str,
    judge_model: str = "claude-haiku-4-5-20251001",
) -> PairwiseResult:
    """
    Run the comparison in both orders; only declare a winner if both agree.
    """
    result_xy = pairwise_judge(
        case_id, user_input, response_x, response_y, label_x, label_y, judge_model
    )
    result_yx = pairwise_judge(
        case_id, user_input, response_y, response_x, label_y, label_x, judge_model
    )

    # Translate result_yx back to x/y framing
    if result_yx.preference == "A":
        flipped = "B"  # "A" in the yx order = y won = B in xy order
    elif result_yx.preference == "B":
        flipped = "A"  # "B" in the yx order = x won = A in xy order
    else:
        flipped = "tie"

    if result_xy.preference == flipped and result_xy.preference != "tie":
        return PairwiseResult(
            case_id, label_x, label_y,
            preference=result_xy.preference,
            confidence="high",
        )
    return PairwiseResult(case_id, label_x, label_y, preference="tie", confidence="low")

from collections import defaultdict
from statistics import mean

def win_rates(results: list[PairwiseResult]) -> dict[str, float]:
    """
    Compute win rate for each model across all comparisons.
    Ties count as 0.5 for each participant.
    """
    wins: dict[str, float] = defaultdict(float)
    totals: dict[str, int] = defaultdict(int)

    for r in results:
        totals[r.model_a] += 1
        totals[r.model_b] += 1
        if r.preference == "A":
            wins[r.model_a] += 1.0
        elif r.preference == "B":
            wins[r.model_b] += 1.0
        else:
            wins[r.model_a] += 0.5
            wins[r.model_b] += 0.5

    return {
        model: wins[model] / totals[model]
        for model in totals
    }

def rank_models(results: list[PairwiseResult]) -> list[tuple[str, float]]:
    """Return models ranked by win rate, descending."""
    rates = win_rates(results)
    return sorted(rates.items(), key=lambda x: x[1], reverse=True)

from scipy.stats import binomtest

def win_rate_significance(
    wins: int,
    losses: int,
    ties: int = 0,
    alpha: float = 0.05,
) -> dict:
    """
    Test whether model A's win rate is significantly different from 50%.

    wins:   number of comparisons where A won
    losses: number of comparisons where B won
    ties:   number of tie comparisons (excluded from the test)
    alpha:  significance level (default 0.05)
    """
    n = wins + losses  # ties excluded from the test
    if n == 0:
        return {"significant": False, "p_value": 1.0, "win_rate": 0.5, "n": 0}

    result = binomtest(wins, n=n, p=0.5, alternative="two-sided")
    win_rate = wins / n

    return {
        "significant": result.pvalue < alpha,
        "p_value": result.pvalue,
        "win_rate": win_rate,
        "n_effective": n,
        "n_ties": ties,
        "verdict": (
            f"Model A significantly better (p={result.pvalue:.3f})" if win_rate > 0.5 and result.pvalue < alpha
            else f"Model B significantly better (p={result.pvalue:.3f})" if win_rate < 0.5 and result.pvalue < alpha
            else f"No significant difference (p={result.pvalue:.3f})"
        ),
    }

def significance_report(results: list) -> dict:
    """Run significance test for each unique (model_a, model_b) pair."""
    from collections import defaultdict
    pairs: dict = defaultdict(lambda: {"wins": 0, "losses": 0, "ties": 0})
    for r in results:
        key = (r.model_a, r.model_b)
        if r.preference == "A":
            pairs[key]["wins"] += 1
        elif r.preference == "B":
            pairs[key]["losses"] += 1
        else:
            pairs[key]["ties"] += 1

    return {
        f"{a} vs {b}": win_rate_significance(**counts)
        for (a, b), counts in pairs.items()
    }
